import Desafios from "./Desafios";
export default function Sobre() {
  return (
    <div>
      <div className="bg-branco w-[60vw] mt-[20vh] h-fit rounded-xl py-5 px-10">
        <h1 className="font-extrabold text-2xl">Sobre mim</h1>
        <p className="text-xl">
          Sou aluno de Desenvolvimento de Sistemas, gosto muito de estudar sobre
          a parte do Front-end
        </p>
      </div>
      <Desafios />
    </div>
  );
}
